namespace InventoryApp.Services;

public class EquipmentItem
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Location { get; set; } = string.Empty;
    public DateTime LastInspected { get; set; }
}

public interface IEquipmentService
{
    Task<List<EquipmentItem>> GetEquipmentAsync();
}

public class EquipmentService : IEquipmentService
{
    public async Task<List<EquipmentItem>> GetEquipmentAsync()
    {
        // Simulate async data access
        await Task.Delay(500);

        return new List<EquipmentItem>
        {
            new() { Id = 1, Name = "Forklift A", Location = "Warehouse 1", LastInspected = new DateTime(2026, 3, 15) },
            new() { Id = 2, Name = "Conveyor Belt B", Location = "Warehouse 2", LastInspected = new DateTime(2026, 4, 20) },
            new() { Id = 3, Name = "Pallet Jack C", Location = "Dock 3", LastInspected = new DateTime(2026, 1, 10) },
            new() { Id = 4, Name = "Crane D", Location = "Yard", LastInspected = new DateTime(2025, 12, 5) },
            new() { Id = 5, Name = "Compressor E", Location = "Maintenance Bay", LastInspected = new DateTime(2026, 5, 1) },
            new() { Id = 6, Name = "Welding Rig F", Location = "Shop Floor", LastInspected = new DateTime(2026, 2, 28) },
            new() { Id = 7, Name = "Generator G", Location = "Utility Room", LastInspected = new DateTime(2026, 4, 10) },
        };
    }
}

@page "/inventory"
@rendermode InteractiveServer
@using InventoryApp.Services
@inject IEquipmentService EquipmentService
@inject PersistentComponentState ApplicationState
@implements IDisposable

<PageTitle>Inventory</PageTitle>

<h1>Equipment Inventory</h1>

@if (equipment is null)
{
    <p><em>Loading inventory...</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Id</th>
                <th>Name</th>
                <th>Location</th>
                <th>Last Inspected</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in equipment)
            {
                <tr>
                    <td>@item.Id</td>
                    <td>@item.Name</td>
                    <td>@item.Location</td>
                    <td>@item.LastInspected.ToShortDateString()</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<EquipmentItem>? equipment;
    private PersistingComponentStateSubscription _persistingSubscription;

    protected override async Task OnInitializedAsync()
    {
        _persistingSubscription = ApplicationState.RegisterOnPersisting(PersistData);

        if (ApplicationState.TryTakeFromJson<List<EquipmentItem>>("equipment", out var restored))
        {
            equipment = restored;
        }
        else
        {
            equipment = await EquipmentService.GetEquipmentAsync();
        }
    }

    private Task PersistData()
    {
        ApplicationState.PersistAsJson("equipment", equipment);
        return Task.CompletedTask;
    }

    public void Dispose()
    {
        _persistingSubscription.Dispose();
    }
}

